const body = $input.first().json.body;

// Pull all vehicle inspection fields
return [{
  json: {
    badge_id:       body.badge_id       ?? 'unknown',
    truck_number:   body.truck_number   ?? 'unknown',
    trailer_number: body.trailer_number ?? '',
    odometer:       Number(body.odometer ?? 0),
    fuel_level:     body.fuel_level     ?? '',
    mode:           body.mode           ?? 'short_haul',
    submitted_at:   body.submitted_at   ?? '',
    timezone:       body.timezone       ?? '',

    // Inspection results
    defect_count:       Number(body.defect_count    ?? 0),
    unchecked_count:    Number(body.unchecked_count ?? 0),
    defect_details:     body.defect_details ?? '',
    inspection_results: body.inspection_results ?? {},
    prev_dvir:          body.prev_dvir ?? 'not_reviewed',

    // Cargo
    cargo_type:   body.cargo_type   ?? '',
    cargo_secure: body.cargo_secure ?? '',
    hazmat:       body.hazmat       ?? 'none',

    // HOS
    hours_today:   body.hours_today   ?? '',
    hours_off:     body.hours_off     ?? '',
    hours_week:    body.hours_week    ?? '',
    haul_duration: body.haul_duration ?? '',
    break_status:  body.break_status  ?? 'na',

    // Flags
    flags: body.flags ?? {},

    // Certifications
    certifications: body.certifications ?? {},

    // Notes
    free_text: body.free_text ?? ''
  }
}];

const d = $input.first().json;
const mode = d.mode ?? 'short_haul';
const defects = Number(d.defect_count ?? 0);

// Base score starts at 0 — vehicle inspection is pass/fail oriented
let score = 0;

// ── DEFECT SCORING ───────────────────────────────────────
// Each defect adds significant weight
score += Math.min(defects * 15, 60);

// Unchecked items are a concern — driver skipped inspection steps
const unchecked = Number(d.unchecked_count ?? 0);
if (unchecked >= 10) score += 20;
else if (unchecked >= 5) score += 10;

// Previous DVIR not reviewed is serious
if (d.prev_dvir === 'not_reviewed') score += 25;

// ── HOS SCORING ──────────────────────────────────────────
const hoursToday = d.hours_today ?? '';
if (hoursToday === '11') score += 20;
else if (hoursToday === '9') score += 10;

const hoursOff = d.hours_off ?? '';
if (hoursOff === '4') score += 20;
else if (hoursOff === '6') score += 10;

// ── LONG HAUL EXTRA ──────────────────────────────────────
if (mode === 'long_haul') {
  if (d.hours_week === 'limit') score += 20;
  else if (d.hours_week === 'high') score += 10;
  if (d.haul_duration === 'max') score += 10;
  else if (d.haul_duration === 'long') score += 5;
}

// ── CARGO ────────────────────────────────────────────────
if (d.cargo_secure === 'unsecured') score += 30;

return [{
  json: {
    ...d,
    risk_score: Math.min(100, Math.round(score))
  }
}];

const d = $input.first().json;

let baseScore = Number(d.risk_score ?? 0);
let bonus = 0;

// ── HARD STOPS ──────────────────────────────────────────
// These force score to 100 regardless of anything else
const hardStop = !!(
  d.flags?.alcohol_8hr ||
  d.flags?.substance_use ||
  d.flags?.hazmat_no_endorse ||
  d.flags?.cargo_unsecured ||
  d.flags?.prev_dvir_missing ||
  d.flags?.break_not_taken
);

// ── SCORED FLAGS ─────────────────────────────────────────
if (d.flags?.hos_violation)     bonus += 25;
if (d.flags?.cognitive_fail)    bonus += 15;
if (d.flags?.vehicle_concern)   bonus += 10;
if (d.flags?.requested_support) bonus += 10;
if (d.flags?.has_defects)       bonus += 10;

// ── FINAL CALCULATION ────────────────────────────────────
const finalScore = hardStop
  ? 100
  : Math.min(100, baseScore + bonus);

return [{
  json: {
    ...d,
    risk_score: finalScore,
    hard_stop: hardStop,
    rule_bonus: bonus
  }
}];

