={
  "model": "tinyllama",
  "prompt": "You are a fleet safety analyst reviewing a commercial vehicle pre-trip inspection report.

Analyze ONLY the information provided below. Do NOT invent details or assumptions.

Return ONLY this JSON. Start with { and end with }. No other text.

Format: {"adjustment": <integer -20 to 20>, "reason": "<one sentence summary of the key safety concern or clearance>"}

Rules:
- adjustment must be an integer between -20 and 20
- Positive adjustment = higher risk, negative = lower risk
- no extra fields, no explanation outside JSON
- Base your assessment on defects, flags, and driver notes only
- If no defects or concerns, return adjustment 0

---

Vehicle: {{ $json.truck_number }}
Trip type: {{ $json.mode }}
Defects found: {{ $json.defect_count }}
Defect details: {{ $json.defect_details || 'None' }}
Previous DVIR: {{ $json.prev_dvir }}
Cargo: {{ $json.cargo_type }} — secured: {{ $json.cargo_secure }}
Hazmat: {{ $json.hazmat }}
Hours driven today: {{ $json.hours_today }}
Hours off before shift: {{ $json.hours_off }}
Driver notes: {{ $json.free_text || 'None' }}

Flags raised:
Alcohol: {{ $json.flags.alcohol_8hr }}
Substance: {{ $json.flags.substance_use }}
HOS violation: {{ $json.flags.hos_violation }}
Vehicle concern: {{ $json.flags.vehicle_concern }}
Cargo unsecured: {{ $json.flags.cargo_unsecured }}
Hazmat no endorsement: {{ $json.flags.hazmat_no_endorse }}",
  "stream": false
}

parameters.jsCode:
const d = $input.first().json;

let parsed = null;

try {
  const raw = d.response ?? '';
  const cleaned = raw.replace(/```json|```/g, '').trim();
  const maybeArray = JSON.parse(cleaned);
  parsed = Array.isArray(maybeArray) ? maybeArray[0] : maybeArray;
} catch (e) {
  parsed = null;
}

const adjustment =
  parsed && typeof parsed.adjustment === 'number'
    ? Math.max(-20, Math.min(20, parsed.adjustment))
    : 0;

const reason = parsed?.reason ?? 'No AI analysis available';

return [{
  json: {
    ...d,
    ai: { adjustment, reason, raw: d.response ?? '' }
  }
}];

const d = $input.first().json;

const risk_score  = $('Flag Rules').first().json.risk_score  ?? 0;
const hard_stop   = $('Flag Rules').first().json.hard_stop   ?? false;
const rule_bonus  = $('Flag Rules').first().json.rule_bonus  ?? 0;
const badge_id    = $('Flag Rules').first().json.badge_id    ?? 'unknown';
const flags       = $('Flag Rules').first().json.flags       ?? {};

const ai_adjustment = d.ai?.adjustment ?? 0;

let final_score = risk_score + ai_adjustment;
final_score = Math.max(0, Math.min(100, final_score));

if (hard_stop) final_score = 100;

let status = 'ok';
if (final_score >= 75) status = 'critical';
else if (final_score >= 55) status = 'warning';
else if (final_score >= 40) status = 'elevated';

return [{
  json: {
    ...d,
    badge_id,
    risk_score,
    hard_stop,
    rule_bonus,
    flags,
    final_score,
    status
  }
}];

